"""Fine Service - Calculates fines for overdue books."""from datetime import datetimefrom ..config.fine_config import FineConfigurationclass FineCalculator:    """    Calculates fines for overdue books using configurable rate tables.    Dependencies are injected via constructor.    """    def __init__(self, config=None):        self.config = config or FineConfiguration()    def calculate_loan_fine(self, loan, current_date=None):        """Calculate fine for a single loan."""        days_overdue = loan.get_days_overdue(current_date)        return self.config.calculate_fine(days_overdue)    def calculate_member_fines(self, member_id, loan_collection, current_date=None):        """        Calculate total fines for a member across all active overdue loans.        Args:            member_id (str): Member ID            loan_collection (LoanCollection): Collection of all loans            current_date (datetime, optional): Reference date        Returns:            float: Total fine amount        """        total_fine = 0.0        active_loans = loan_collection.get_active_loans_for_member(member_id)        for loan in active_loans:            if loan.is_overdue(current_date):                total_fine += self.calculate_loan_fine(loan, current_date)        return total_fine